```rust
use std::env;
use std::ffi::CString;
use std::fs::OpenOptions;
use std::io::{self, Write};
use std::os::unix::fs::OpenOptionsExt;
use std::os::unix::io::{AsRawFd, FromRawFd, RawFd};
use std::os::unix::process::CommandExt;
use std::process::Command;

const FILENAME: &str = "nohup.out";
const EXIT_NOEXEC: i32 = 126;
const EXIT_NOTFOUND: i32 = 127;
const EXIT_MISC: i32 = 127;

fn main() {
    let args: Vec<String> = env::args().collect();

    // Handle -- and skip options (nohup takes no options)
    let mut start = 1;
    if start < args.len() && args[start] == "--" {
        start += 1;
    }

    if start >= args.len() {
        eprintln!("usage: nohup [--] utility [arguments]");
        std::process::exit(EXIT_MISC);
    }

    let cmd_args = &args[start..];

    // If stdout is a terminal, redirect to nohup.out
    if isatty(io::stdout().as_raw_fd()) {
        dofile();
    }

    // If stderr is a terminal, dup stdout to stderr
    if isatty(io::stderr().as_raw_fd()) {
        // dup2(STDOUT_FILENO, STDERR_FILENO)
        unsafe {
            let ret = libc::dup2(io::stdout().as_raw_fd(), libc::STDERR_FILENO);
            if ret == -1 {
                eprintln!("{}: {}", cmd_args[0], io::stderr());
                std::process::exit(EXIT_MISC);
            }
        }
    }

    // Ignore SIGHUP
    unsafe {
        libc::signal(libc::SIGHUP, libc::SIG_IGN as _);
    }

    // Exec the command
    let cmd_name = CString::new(cmd_args[0].as_bytes()).unwrap_or_else(|_| {
        eprintln!("usage: nohup [--] utility [arguments]");
        std::process::exit(EXIT_MISC);
    });

    let mut cmd = Command::new(&cmd_name);
    for arg in &cmd_args[1..] {
        cmd.arg(arg);
    }

    match cmd.exec() {
        Ok(_) => unreachable!(),
        Err(e) => {
            let exit_status = if e.kind() == std::io::ErrorKind::NotFound {
                EXIT_NOTFOUND
            } else {
                EXIT_NOEXEC
            };
            eprintln!("{}: {}", cmd_args[0], e);
            std::process::exit(exit_status);
        }
    }
}

fn isatty(fd: RawFd) -> bool {
    unsafe { libc::isatty(fd) != 0 }
}

fn dofile() {
    // Try opening nohup.out in current directory
    let mut path = FILENAME;
    let fd = match open_nohup_out(FILENAME) {
        Ok(fd) => fd,
        Err(_) => {
            // Try $HOME/nohup.out
            if let Ok(home) = env::var("HOME") {
                if !home.is_empty() {
                    let home_path = format!("{}/{}", home, FILENAME);
                    path = &home_path;
                    match open_nohup_out(&home_path) {
                        Ok(fd) => fd,
                        Err(_) => {
                            eprintln!("can't open a nohup.out file");
                            std::process::exit(EXIT_MISC);
                        }
                    }
                } else {
                    eprintln!("can't open a nohup.out file");
                    std::process::exit(EXIT_MISC);
                }
            } else {
                eprintln!("can't open a nohup.out file");
                std::process::exit(EXIT_MISC);
            }
        }
    };

    // dup2(fd, STDOUT_FILENO)
    unsafe {
        if libc::dup2(fd, libc::STDOUT_FILENO) == -1 {
            eprintln!("{}", io::Error::last_os_error());
            std::process::exit(EXIT_MISC);
        }
    }

    // Close the extra fd
    unsafe { libc::close(fd); }

    eprintln!("appending output to {}", path);
}

fn open_nohup_out(path: &str) -> io::Result<RawFd> {
    let file = OpenOptions::new()
        .read(true)
        .write(true)
        .create(true)
        .append(true)
        .mode(0o600)
        .open(path)?;

    Ok(file.into_raw_fd())
}
