use std::env;
use std::fs::{self, File};
use std::io::{self, Read};
use std::process;
use std::ffi::OsString;

fn main() {
    let args: Vec<OsString> = env::args_os().collect();
    let mut prog = &args[..1];
    let mut flags = &args[1..];

    let mut doline = false;
    let mut doword = false;
    let mut dochar = false;
    let mut domulti = false;
    let mut dolongline = false;

    // Parse flags
    let mut files = Vec::new();
    while let Some(flag) = flags.first() {
        let flag_str = flag.to_string_lossy();
        if flag_str.starts_with('-') && flag_str.len() > 1 {
            for ch in flag_str[1..].chars() {
                match ch {
                    'l' => doline = true,
                    'w' => doword = true,
                    'c' => { dochar = true; domulti = false; }
                    'L' => dolongline = true,
                    'm' => { domulti = true; dochar = false; }
                    _ => {
                        eprintln!("usage: wc [-c | -m] [-Llw] [file ...]");
                        process::exit(1);
                    }
                }
            }
            flags = &flags[1..];
        } else {
            break;
        }
    }

    // Remaining args are files
    for f in flags {
        files.push(f.clone());
    }

    // Default: lines + words + chars
    if !doline && !doword && !dochar && !domulti && !dolongline {
        doline = true;
        doword = true;
        dochar = true;
    }

    // Process files
    let mut errors = 0;
    let mut total_lines: u64 = 0;
    let mut total_words: u64 = 0;
    let mut total_chars: u64 = 0;
    let mut total_longline: u64 = 0;

    if files.is_empty() {
        let result = count_file(None);
        match result {
            Ok((lines, words, chars, longline)) => {
                total_lines += lines;
                total_words += words;
                total_chars += chars;
                total_longline = longline;
                show_count(None, lines, words, chars, longline, doline, doword, dochar || domulti, dolongline);
            }
            Err(_) => errors += 1,
        }
    } else {
        for file in &files {
            let result = count_file(Some(file));
            match result {
                Ok((lines, words, chars, longline)) => {
                    total_lines += lines;
                    total_words += words;
                    total_chars += chars;
                    if longline > total_longline {
                        total_longline = longline;
                    }
                    show_count(Some(file), lines, words, chars, longline, doline, doword, dochar || domulti, dolongline);
                }
                Err(_) => errors += 1,
            }
        }

        if files.len() > 1 {
            show_count(Some(&OsString::from("total")), total_lines, total_words, total_chars, total_longline, doline, doword, dochar || domulti, dolongline);
        }
    }

    process::exit(if errors == 0 { 0 } else { 1 });
}

